import React, { useState } from 'react';
import PropTypes from 'prop-types';
import { ListGroup, ListGroupItem, Button } from 'reactstrap';
import IosPlay from 'react-ionicons/lib/IosPlay';
import IosPause from 'react-ionicons/lib/IosPause';

const CollectionItem = ({
  type = 'article',
  episodes = [],
  title = '',
  content = '',
}) => {
  const [playing, setPlaying] = useState(-1);

  return (
    <div className="collection-item">
      <div className="collection-item-title">{title}</div>
      <div className="embed-responsive embed-responsive-16by9">
        {type === 'article' ? null : (
          <iframe
            title={title}
            className="embed-responsive-item"
            src={episodes[0].mediaUrl}
            frameBorder="0"
            allow="accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        )}
      </div>
      <div className="collection-item-content">
        <ListGroup flush>
          {episodes.map(item => (
            <ListGroupItem key={item.id} className="playlist-item">
              Part {item.id}: {item.title}
              <IosPlay
                onClick={() => setPlaying(item.id)}
                fontSize="1.25em"
                color="#666"
              />
            </ListGroupItem>
          ))}
        </ListGroup>
      </div>
    </div>
  );
};

CollectionItem.propTypes = {
  type: PropTypes.string,
  episodes: PropTypes.arrayOf(PropTypes.object),
  title: PropTypes.string,
  content: PropTypes.string,
};

export default CollectionItem;
